const auth = $('Execute ClubSpark Auth Session').first().json ?? {};
const html = String($input.first().json?.data ?? $input.first().json?.body ?? '');
if (!html.trim()) {
  throw new Error('The authenticated fetch did not return any HTML.');
}
if (/Sign in|Log in/i.test(html) && /auth\.clubspark\.uk|mylta\.my\.site\.com/i.test(html)) {
  throw new Error('The returned HTML is still the ClubSpark/LTA sign-in page.');
}
const hasMembersTable = /members-table/i.test(html);
const hasAdminMarkers = /Contact Options|Reset filters|Export CSV|Membership/i.test(html);
if (!hasMembersTable && !hasAdminMarkers) {
  throw new Error('The fetched HTML does not look like the authenticated ClubSpark members page.');
}
return [{
  json: {
    authenticated: true,
    auth_target_url: auth.targetUrl,
    auth_authenticated_url: auth.authenticatedUrl,
    cookie_count: auth.cookieCount,
    fetch_verified_url: 'https://clubspark.lta.org.uk/AvondaleTennisClub/Admin/Membership/Members',
    members_table_detected: hasMembersTable,
    html_snippet: html.replace(/\s+/g, ' ').slice(0, 400),
  },
}];
